import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';

interface Project {
  id: number;
  name: string;
  description: string;
  status: string;
  startDate: string;
  endDate: string;
  budget: number;
  spent: number;
  team: string[];
}

export default function ProjectDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [project, setProject] = useState<Project | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockProject: Project = {
      id: Number(id),
      name: 'Website Redesign',
      description: 'Complete redesign of company website',
      status: 'active',
      startDate: '2026-01-01',
      endDate: '2026-06-30',
      budget: 50000,
      spent: 32000,
      team: ['John Doe', 'Jane Smith', 'Bob Johnson'],
    };
    
    setProject(mockProject);
    setLoading(false);
  }, [id]);

  if (loading) return <div className="p-6">Loading...</div>;
  if (!project) return <div className="p-6">Project not found</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">{project.name}</h1>
        <Button variant="outline" onClick={() => navigate('/projects')}>Back</Button>
      </div>

      <div className="grid gap-6 md:grid-cols-2">
        <div className="p-4 border rounded-lg">
          <h3 className="font-semibold mb-4">Project Details</h3>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Description</p>
              <p>{project.description}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Status</p>
              <p className="font-medium capitalize">{project.status}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Duration</p>
              <p>{new Date(project.startDate).toLocaleDateString()} - {new Date(project.endDate).toLocaleDateString()}</p>
            </div>
          </div>
        </div>

        <div className="p-4 border rounded-lg">
          <h3 className="font-semibold mb-4">Budget</h3>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Total Budget</p>
              <p className="font-medium text-lg">${project.budget.toLocaleString()}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Spent</p>
              <p className="font-medium text-lg">${project.spent.toLocaleString()}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Remaining</p>
              <p className="font-medium text-lg text-green-600">${(project.budget - project.spent).toLocaleString()}</p>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div
                className="bg-blue-600 h-2 rounded-full"
                style={{ width: `${(project.spent / project.budget) * 100}%` }}
              ></div>
            </div>
          </div>
        </div>
      </div>

      <div className="p-4 border rounded-lg">
        <h3 className="font-semibold mb-4">Team Members</h3>
        <div className="space-y-2">
          {project.team.map((member, i) => (
            <div key={i} className="p-2 bg-gray-50 rounded">{member}</div>
          ))}
        </div>
      </div>
    </div>
  );
}
